  private bool IsValidShopOffer(SkinShopOfferInfo offer)
  {
    if (offer.Price <= 0)
      return false;
    return offer.Currency == "coins" || offer.Currency == "premium";
  }

  private int GetLowestOfferPrice(SkinShopItemInfo shopItem)
  {
    return shopItem.Offers.Where<SkinShopOfferInfo>(new Func<SkinShopOfferInfo, bool>(this.IsValidShopOffer)).Select<SkinShopOfferInfo, int>((Func<SkinShopOfferInfo, int>) (offer => offer.Price)).DefaultIfEmpty<int>(int.MaxValue).Min();
  }

